-- BrandKraf — BM translation batch 12: FULL-DEPTH (5 articles, net-new). Run AFTER blog-i18n-migration.sql.
-- Faithful, section-for-section translations of the English articles. Content dollar-quoted ($ms$...$ms$).

update public.blog_posts set
  title_ms = 'Masa Terbaik untuk Menyiar di Media Sosial di Malaysia',
  excerpt_ms = 'Bila anda menyiar mempengaruhi sejauh mana kandungan anda mencapai. Pelajari masa terbaik umum untuk menyiar di Malaysia — dan cara mencari tetingkap tepat yang berfungsi untuk penonton anda.',
  content_ms = $ms$<p>Menyiar kandungan hebat pada masa yang salah bermakna lebih sedikit orang melihatnya dalam minit-minit awal yang penting itu — dan penglibatan awal yang mencetuskan jangkauan lebih luas. Walaupun tiada satu jam ajaib, terdapat corak yang boleh dipercayai untuk penonton Malaysia, serta cara mudah untuk mencari corak anda sendiri.</p>
<blockquote>Masa terbaik untuk menyiar ialah apabila penonton anda berjaga, menyusur, dan bersedia untuk terlibat — bukan apabila ia mudah untuk anda.</blockquote>
<h2>Mengapa masa penting</h2>
<p>Kebanyakan platform menunjukkan siaran anda kepada penonton awal yang kecil dan mengembangkan jangkauan berdasarkan penglibatan awal. Jika anda menyiar apabila penonton anda tidur atau sibuk, tetingkap awal itu terbazir. Menyiar apabila mereka aktif memberi kandungan anda permulaan terbaik yang mungkin.</p>
<h2>Tetingkap terbaik umum di Malaysia</h2>
<p>Penonton Malaysia biasanya paling aktif dalam tetingkap ini (waktu tempatan):</p>
<ul><li><strong>Awal pagi</strong> (7–9 pagi) — semasa perjalanan ke kerja dan susur kopi pertama.</li><li><strong>Waktu rehat tengah hari</strong> (12–2 petang) — puncak harian yang boleh dipercayai.</li><li><strong>Waktu petang</strong> (7–10 malam) — tetingkap terbesar, selepas kerja dan makan malam.</li></ul>
<p>Hujung minggu beralih lewat sedikit dan boleh menjadi kukuh untuk kandungan gaya hidup dan F&B.</p>
<h2>Penonton anda adalah unik</h2>
<p>Ini adalah titik permulaan, bukan peraturan. Penonton khusus anda mungkin berbeza berdasarkan pekerjaan, umur, dan tabiat mereka. Satu-satunya cara untuk pasti ialah menyemak data anda sendiri — anggap tetingkap umum sebagai hipotesis untuk diuji.</p>
<h2>Cari masa terbaik sebenar anda</h2>
<p>Gunakan analitik platform anda (Instagram Insights, TikTok Analytics, dll.) untuk melihat bila pengikut anda dalam talian dan bila siaran lepas anda berprestasi terbaik. Siar sekitar tetingkap itu, kemudian perhalusi. Analitik anda mengalahkan mana-mana carta generik. Lihat panduan kami tentang <a href="/ms/blog/social-media-metrics-that-matter">metrik media sosial</a>.</p>
<h2>Kekonsistenan mengalahkan masa yang sempurna</h2>
<p>Jangan taksub dengan minit yang sempurna. Menyiar secara konsisten dalam tetingkap yang lebih kurang betul jauh lebih penting daripada menepati masa yang tepat sekali. Jadual yang boleh dipercayai, dirancang dengan <a href="/ms/blog/content-calendar-guide">kalendar kandungan</a>, menang dari masa ke masa.</p>
<h2>Soalan lazim</h2>
<h3>Adakah satu masa terbaik untuk menyiar?</h3>
<p>Tidak. Ia bergantung pada penonton anda. Waktu petang (7–10 malam) ialah tetingkap umum yang kukuh di Malaysia, tetapi uji data anda sendiri.</p>
<h3>Bagaimana saya cari masa terbaik saya?</h3>
<p>Semak analitik platform anda untuk bila pengikut anda dalam talian dan bila siaran lepas berprestasi terbaik, kemudian siar sekitar masa itu.</p>
<h3>Adakah masa menyiar lebih penting daripada kandungan?</h3>
<p>Tidak — kualiti kandungan paling penting. Masa mengoptimumkan kandungan yang baik; ia tidak boleh menyelamatkan kandungan yang lemah.</p>
<h3>Patutkah saya menyiar pada hujung minggu?</h3>
<p>Selalunya ya, terutamanya untuk gaya hidup, F&B, dan hiburan. Uji tetingkap hujung minggu untuk penonton anda.</p>
<p>BrandKraf mengoptimumkan dan menguruskan penyiaran untuk jenama Malaysia. Terokai <a href="/ms/guides/social-media-growth">panduan pertumbuhan media sosial</a> kami, <a href="/ms/portfolio/social-media-management">perkhidmatan media sosial</a> kami, atau <a href="/ms/contact">hubungi kami</a>.</p>$ms$
where slug = 'best-time-to-post-social-media-malaysia';

update public.blog_posts set
  title_ms = 'Berapa Kerap Anda Patut Menyiar di Media Sosial?',
  excerpt_ms = 'Menyiar terlalu sedikit dan anda hilang; terlalu banyak dan anda terbakar. Pelajari berapa kerap untuk menyiar di setiap platform — dan mengapa kekonsistenan jauh lebih penting daripada kekerapan.',
  content_ms = $ms$<p>"Berapa kerap saya patut menyiar?" ialah salah satu soalan media sosial paling biasa — dan jawapannya bukan "sebanyak mungkin". Kekerapan yang betul ialah yang boleh anda kekalkan sambil mengekalkan kualiti tinggi. Inilah cara untuk memikirkannya.</p>
<blockquote>Kekerapan penyiaran terbaik ialah yang tertinggi yang boleh anda kekalkan tanpa menjatuhkan kualiti. Kekonsistenan mengalahkan intensiti.</blockquote>
<h2>Kekonsistenan lebih penting daripada kekerapan</h2>
<p>Menyiar tiga kali seminggu setiap minggu mengalahkan menyiar setiap hari selama dua minggu kemudian senyap. Algoritma dan penonton anda kedua-duanya memberi ganjaran kepada kebolehpercayaan. Pilih kadar yang boleh anda kekalkan pada minggu paling sibuk anda, bukan minggu paling bersemangat anda.</p>
<h2>Garis panduan umum mengikut platform</h2>
<ul><li><strong>Instagram</strong> — beberapa siaran suapan atau Reels seminggu, tambah Stories setiap hari.</li><li><strong>TikTok</strong> — penyiaran kerap (selalunya setiap hari) memberi ganjaran kepada algoritma, jika anda boleh mengekalkan kualiti.</li><li><strong>Facebook</strong> — beberapa kali seminggu.</li><li><strong>LinkedIn</strong> — dua hingga lima kali seminggu.</li><li><strong>YouTube</strong> — bentuk panjang mingguan, lebih kerap untuk Shorts.</li></ul>
<p>Ini adalah titik permulaan — laraskan kepada kapasiti dan hasil anda.</p>
<h2>Kualiti mengatasi kuantiti (sentiasa)</h2>
<p>Lebih banyak siaran hanya membantu jika ia baik. Membanjiri suapan anda dengan kandungan lemah boleh menjejaskan penglibatan dan jangkauan. Lebih baik menyiar kurang kerap dan menjadikan setiap keping bermakna. Satu siaran yang kukuh mengalahkan lima yang mudah dilupakan.</p>
<h2>Volum membantu pada platform penemuan</h2>
<p>Pada platform yang dibina sekitar penemuan — terutamanya TikTok dan Reels — lebih banyak kandungan berkualiti memang meningkatkan peluang anda untuk meletup, kerana setiap siaran ialah peluang baharu untuk jangkauan. Kata kuncinya ialah volum <em>berkualiti</em>, dicapai melalui <a href="/ms/blog/how-to-batch-create-content">berkelompok</a>.</p>
<h2>Padankan kekerapan dengan kapasiti anda</h2>
<p>Jadilah realistik. Jika menyiar setiap hari bermakna terbakar atau menyiar bahan pengisi, kurangkan. Tabiat tiga kali seminggu yang mampan yang anda kekalkan selama setahun akan jauh mengatasi jadual bercita-cita tinggi yang anda tinggalkan dalam sebulan.</p>
<h2>Soalan lazim</h2>
<h3>Adakah buruk untuk menyiar terlalu banyak?</h3>
<p>Boleh jadi, jika kualiti menurun atau anda membebankan penonton anda. Kualiti yang mampan mengalahkan volum yang tidak mampan.</p>
<h3>Adakah menyiar lebih banyak akan mengembangkan saya lebih pantas?</h3>
<p>Pada platform penemuan, lebih banyak kandungan berkualiti boleh membantu. Tetapi siaran lemah yang kerap menjejaskan lebih daripada membantu.</p>
<h3>Bagaimana jika saya hanya boleh menyiar dua kali seminggu?</h3>
<p>Itu tidak mengapa — jadilah konsisten dan jadikan siaran itu cemerlang. Kekonsistenan pada mana-mana kadar mengalahkan letusan yang berselerak.</p>
<h3>Bagaimana saya mengekalkan kekerapan yang lebih tinggi?</h3>
<p>Hasilkan kandungan secara berkelompok dan gunakan kalendar supaya anda menghasilkan secara pukal dan menyiar secara autopilot.</p>
<p>BrandKraf mengekalkan jenama Malaysia konsisten tanpa keletihan. Terokai <a href="/ms/guides/social-media-growth">panduan pertumbuhan media sosial</a> kami, <a href="/ms/portfolio/social-media-management">perkhidmatan media sosial</a> kami, atau <a href="/ms/contact">hubungi kami</a>.</p>$ms$
where slug = 'how-often-to-post-on-social-media';

update public.blog_posts set
  title_ms = 'Pemasaran Facebook untuk Perniagaan: Panduan Pertumbuhan Organik',
  excerpt_ms = 'Facebook jauh daripada mati — ia masih besar di Malaysia. Pelajari cara menggunakan Facebook secara organik dengan Halaman, Kumpulan, video, dan komuniti untuk mengembangkan perniagaan anda.',
  content_ms = $ms$<p>Semua orang bercakap tentang TikTok dan Instagram, tetapi Facebook kekal salah satu platform paling banyak digunakan di Malaysia, terutamanya dalam kalangan penonton lebih tua dan pinggir bandar. Jika pelanggan anda di sana, pemasaran Facebook organik masih sangat berbaloi dengan masa anda. Inilah cara melakukannya dengan baik.</p>
<blockquote>Facebook bukan tempat trend dilahirkan — ia tempat penonton Malaysia yang besar dan setia masih menghabiskan masa mereka. Jangan ketepikannya.</blockquote>
<h2>Mengapa Facebook masih penting di Malaysia</h2>
<p>Facebook mempunyai jangkauan yang sangat besar merentasi demografi Malaysia, terutamanya penonton berumur 30-an ke atas dan komuniti tempatan. Bagi banyak perniagaan — terutamanya perkhidmatan tempatan, F&B, dan runcit — penonton itu tepat seperti yang mereka mahukan. Marketplace dan Kumpulan juga menjadikannya berkuasa untuk perdagangan tempatan.</p>
<h2>Optimumkan Halaman Facebook anda</h2>
<p>Halaman anda ialah hab anda. Lengkapkan setiap butiran — perkhidmatan, waktu, hubungan, dan penerangan yang jelas — tambah imej profil dan kulit yang kukuh, dan kekalkan maklumat anda tepat. Halaman yang lengkap dan aktif membina kepercayaan dan membantu anda ditemui.</p>
<h2>Video dan Reels berfungsi di sini juga</h2>
<p>Facebook mengutamakan video dan mempunyai Reels sendiri, yang mencapai melangkaui pengikut anda sama seperti di Instagram. Guna semula video bentuk pendek anda ke Facebook untuk memanfaatkan penonton besarnya — lihat <a href="/ms/blog/how-to-repurpose-content">panduan mengguna semula</a> kami.</p>
<h2>Gunakan Kumpulan Facebook</h2>
<p>Kumpulan ialah salah satu alat organik terkuat Facebook. Anda boleh membina komuniti sekitar jenama anda, atau menyertai secara tulen dalam Kumpulan tempatan dan niche yang relevan untuk membina kewibawaan dan jangkauan — tanpa spam. Penyertaan yang membantu memperoleh kepercayaan dan pelanggan.</p>
<h2>Libatkan diri dan bina komuniti</h2>
<p>Facebook memberi ganjaran kepada interaksi bermakna. Balas komen dan mesej, siarkan kandungan yang mencetuskan perbincangan, dan pupuk rasa komuniti. Penonton Halaman yang terlibat melihat lebih banyak kandungan anda dan merujuk orang lain.</p>
<h2>Gabungkan organik dengan kesedaran tempatan</h2>
<p>Organik membina asas; apabila bersedia, iklan Facebook menambah jangkauan dengan penyasaran tempatan yang tepat. Kedua-duanya berfungsi bersama — kandungan organik yang kukuh menjadikan iklan anda lebih berkesan. Lihat <a href="/ms/blog/facebook-meta-ads-beginners-guide">panduan Meta Ads</a> kami.</p>
<h2>Soalan lazim</h2>
<h3>Adakah Facebook masih relevan pada 2026?</h3>
<p>Ya — terutamanya di Malaysia, di mana ia mengekalkan penonton yang besar dan aktif, terutamanya dalam kalangan pengguna 30-an ke atas dan komuniti tempatan.</p>
<h3>Apa yang berprestasi terbaik secara organik di Facebook?</h3>
<p>Video dan Reels, siaran dipacu komuniti, dan kandungan yang mencetuskan perbincangan. Kumpulan amat berkuasa.</p>
<h3>Patutkah saya gunakan Halaman atau Kumpulan?</h3>
<p>Kedua-duanya — Halaman sebagai hab anda dan Kumpulan untuk membina komuniti. Ia memenuhi tujuan berbeza yang saling melengkapi.</p>
<h3>Adakah jangkauan organik di Facebook rendah?</h3>
<p>Jangkauan organik terhad, jadi bergantung pada video, Kumpulan, dan penglibatan — dan tambah iklan disasarkan apabila anda mahu berskala.</p>
<p>BrandKraf menjalankan strategi Facebook untuk perniagaan Malaysia. Terokai <a href="/ms/guides/social-media-growth">panduan pertumbuhan media sosial</a> kami, <a href="/ms/portfolio/social-media-management">perkhidmatan media sosial</a> kami, atau <a href="/ms/contact">hubungi kami</a>.</p>$ms$
where slug = 'facebook-marketing-for-business';

update public.blog_posts set
  title_ms = 'Metrik Media Sosial yang Benar-benar Penting',
  excerpt_ms = 'Suka bukan matlamat. Pelajari metrik media sosial mana yang benar-benar meramal pertumbuhan perniagaan — jangkauan, kadar penglibatan, simpanan, perkongsian, dan penukaran — dan apa yang perlu diabaikan.',
  content_ms = $ms$<p>Mudah untuk taksub dengan suka dan jumlah pengikut, tetapi nombor itu jarang memberitahu anda sama ada media sosial anda berfungsi. Metrik yang penting ialah yang dikaitkan dengan jangkauan, penglibatan sebenar, dan akhirnya jualan. Inilah apa yang perlu dijejaki dan apa yang perlu diabaikan.</p>
<blockquote>Metrik kesombongan membuatkan anda berasa baik. Metrik sebenar membuatkan anda wang. Ketahui perbezaannya.</blockquote>
<h2>Metrik kesombongan vs metrik sebenar</h2>
<p>Jumlah pengikut dan suka ialah metrik kesombongan — bagus untuk dilihat, tetapi ia tidak meramal hasil perniagaan dengan boleh dipercayai. Metrik sebenar — jangkauan, kadar penglibatan, simpanan, perkongsian, klik, dan penukaran — memberitahu anda sama ada kandungan anda benar-benar berfungsi. Fokuskan perhatian anda di situ.</p>
<h2>Jangkauan dan tera</h2>
<p>Jangkauan (orang unik yang melihat kandungan anda) menunjukkan sejauh mana anda tersebar. Jangkauan yang berkembang bermakna kandungan anda ditolak kepada penonton baharu — tanda kail dan penglibatan anda berfungsi. Jejaki ia dari masa ke masa, bukan siaran demi siaran.</p>
<h2>Kadar penglibatan</h2>
<p>Kadar penglibatan (interaksi berbanding jangkauan atau pengikut) ialah isyarat kesihatan yang lebih baik daripada suka mentah. Ia memberitahu anda sama ada orang benar-benar ambil berat. Jejaki ia dengan <a href="/ms/blog/engagement-rate-calculator">kalkulator kadar penglibatan</a> kami dan perhatikan arah alirannya.</p>
<h2>Simpanan dan perkongsian</h2>
<p>Simpanan dan perkongsian ialah isyarat penglibatan paling bernilai — ia bermakna kandungan anda berguna atau berbaloi disebarkan, dan ia memacu jangkauan tambahan terbanyak. Utamakan kandungan yang memperolehnya.</p>
<h2>Klik dan penukaran</h2>
<p>Akhirnya, media sosial patut memacu perniagaan. Jejaki klik pautan, lawatan profil, DM, dan penukaran (jualan, petunjuk, pendaftaran). Ini menghubungkan kandungan anda dengan hasil — dan inilah yang benar-benar penting. Ukur ia dengan <a href="/ms/blog/ga4-analytics-beginners-guide">Google Analytics</a>.</p>
<h2>Semak secara kerap dan bertindak</h2>
<p>Metrik hanya berguna jika ia mengubah apa yang anda lakukan. Semak setiap bulan, kenal pasti kandungan berprestasi terbaik anda, dan buat lebih banyak daripadanya. Semakan bulanan ringkas — apa yang berkembang, apa yang gagal, apa yang perlu diulang — mengalahkan taksub dengan nombor harian.</p>
<h2>Soalan lazim</h2>
<h3>Apa metrik media sosial paling penting?</h3>
<p>Ia bergantung pada matlamat anda, tetapi kadar penglibatan dan penukaran paling memberitahu. Simpanan dan perkongsian ialah isyarat kualiti kandungan yang kukuh.</p>
<h3>Patutkah saya ambil berat tentang jumlah pengikut langsung?</h3>
<p>Hanya secara longgar. Penonton yang lebih kecil, terlibat, dan menukar bernilai jauh lebih daripada yang besar dan pasif.</p>
<h3>Berapa kerap saya patut menyemak metrik saya?</h3>
<p>Semakan bulanan yang fokus sudah cukup untuk kebanyakan perniagaan, dengan semakan pantas semasa kempen.</p>
<h3>Apa metrik paling terlebih nilai?</h3>
<p>Suka dan jumlah pengikut. Ia berasa baik tetapi jarang meramal hasil perniagaan sebenar.</p>
<p>BrandKraf melaporkan metrik yang penting untuk jenama Malaysia. Terokai <a href="/ms/guides/social-media-growth">panduan pertumbuhan media sosial</a> kami, <a href="/ms/portfolio/social-media-management">perkhidmatan media sosial</a> kami, atau <a href="/ms/contact">hubungi kami</a>.</p>$ms$
where slug = 'social-media-metrics-that-matter';

update public.blog_posts set
  title_ms = 'Cara Mengendalikan Komen Negatif di Media Sosial',
  excerpt_ms = 'Komen negatif tidak dapat dielakkan. Pelajari cara membalas kritikan, troll, dan aduan secara profesional — dan menukar saat tidak gembira menjadi kemenangan membina kepercayaan.',
  content_ms = $ms$<p>Lambat-laun, setiap jenama mendapat komen negatif — aduan, kritikan, atau troll terang-terangan. Cara anda membalas diperhatikan oleh semua orang, dan jika dikendalikan dengan baik, ia sebenarnya boleh membina kepercayaan. Inilah rangka kerja yang tenang dan profesional untuk menangani kenegatifan dalam talian.</p>
<blockquote>Semua orang melihat cara anda mengendalikan komen marah itu. Balas dengan baik, dan aduan itu menjadi iklan terbaik anda.</blockquote>
<h2>Jangan panik atau padam (biasanya)</h2>
<p>Naluri pertama anda mungkin untuk memadam atau membalas dengan marah — tahan kedua-duanya. Memadam aduan yang sah kelihatan seperti anda menyembunyikan sesuatu, dan bertindak balas secara emosi menjadikannya lebih teruk. Tarik nafas dan balas dengan teliti. Penonton menilai ketenangan anda, bukan hanya aduan.</p>
<h2>Asingkan aduan daripada troll</h2>
<p>Tidak semua kenegatifan adalah sama. Aduan yang tulen layak mendapat respons yang sebenar dan membantu. Troll yang mencari reaksi paling baik dikendalikan dengan balasan ringkas dan sopan atau sekadar diabaikan. Belajar membezakannya sebelum anda membalas.</p>
<h2>Balas aduan dengan empati</h2>
<p>Untuk aduan sebenar: akui isu itu, minta maaf di mana sesuai, dan tawarkan untuk membetulkannya — sebaik-baiknya mengalihkan perbualan terperinci ke DM atau e-mel. Balasan awam yang tenang dan prihatin menunjukkan kepada semua orang yang memerhati bahawa anda menjaga pelanggan. Ini selalunya memenangi lebih kepercayaan daripada tiada aduan langsung.</p>
<h2>Bawa ke luar talian untuk menyelesaikan</h2>
<p>Selesaikan butiran secara peribadi. Balasan awam ringkas ("Maaf mendengar perkara ini — kami telah menghantar DM kepada anda untuk menyelesaikannya segera") tambah pembetulan peribadi yang tulen ialah piawai emas. Ia menunjukkan akauntabiliti tanpa pertikaian awam berbalas-balas.</p>
<h2>Tahu bila hendak mengabaikan atau menyekat</h2>
<p>Untuk troll, spam, atau penderaan, jangan terlibat. Abaikan, sembunyikan, atau sekat mengikut keperluan. Anda tidak wajib berdebat, dan memberi makan troll hanya menguatkan mereka. Lindungi komuniti dan ketenangan fikiran anda.</p>
<h2>Sediakan dasar yang ringkas</h2>
<p>Putuskan lebih awal cara anda akan mengendalikan aduan, troll, dan penderaan, dan siapa yang membalas. Dasar yang jelas bermakna respons yang tenang dan konsisten dan bukannya yang panik — terutamanya bernilai jika anda menguruskan akaun yang sibuk atau pasukan.</p>
<h2>Soalan lazim</h2>
<h3>Patutkah saya padam komen negatif?</h3>
<p>Umumnya tidak untuk aduan yang sah — tangani ia sebaliknya. Sembunyikan atau padam spam, penderaan, dan trolling.</p>
<h3>Berapa pantas saya patut membalas aduan?</h3>
<p>Dengan pantas. Respons yang segera dan berempati mengehadkan kerosakan dan menunjukkan anda ambil berat.</p>
<h3>Bagaimana jika kritikan itu tidak adil?</h3>
<p>Kekal tenang dan profesional. Balas sekali dengan pihak anda secara sopan; jangan terjebak dalam pertikaian awam.</p>
<h3>Bagaimana saya mengendalikan troll?</h3>
<p>Jangan beri mereka makan. Balasan ringkas atau sekadar mengabaikan, menyembunyikan, atau menyekat ialah yang terbaik. Jangan sekali-kali berdebat dengan komen niat jahat.</p>
<p>BrandKraf menguruskan komuniti dan reputasi untuk jenama Malaysia. Terokai <a href="/ms/guides/social-media-growth">panduan pertumbuhan media sosial</a> kami, <a href="/ms/portfolio/social-media-management">perkhidmatan media sosial</a> kami, atau <a href="/ms/contact">hubungi kami</a>.</p>$ms$
where slug = 'handling-negative-comments-social-media';
